    class Solution {

        public static void main(String[] args) {
            System.out.println(getMinTimeToObtainScore(new int[][] {{1, 3}, {5, 10}, {3, 12}}, 3, 10));//3
            System.out.println(getMinTimeToObtainScore(new int[][] {{1, 3}, {5, 10}, {3, 12}}, 9, 10));//9
            System.out.println(getMinTimeToObtainScore(new int[][] {{12, 10}, {16, 10}, {20, 10}, {24, 10}, {8, 3}}, 40, 21));//36
        }

        public static int getMinTimeToObtainScore(int[][] arr, int totalTime, int requiredScore) {
            int arrSize = arr.length;
            int[][] dp = new int[arrSize + 1][totalTime + 1];

            for (int i = 1; i <= arrSize; i++) {
                int time = arr[i - 1][0];
                int score = arr[i - 1][1];

                for (int t = 0; t <= totalTime; t++) {
                    dp[i][t] = dp[i - 1][t];
                    if (t >= time) {
                        dp[i][t] = Math.max(
                                dp[i][t],
                                dp[i - 1][t - time] + score
                        );
                    }
                }
            }

            int maxScore = dp[arrSize][totalTime];
            if (maxScore < requiredScore) {
                return -1;
            } else {
                for (int t = 0; t <= totalTime; t++) {
                    if (dp[arrSize][t] >= maxScore) {
                        return t;
                    }
                }
                return totalTime;
            }
        }
    }

void helper(vector<pair<int,int>>& arr,int i,int t,int score,int& max_score,int& min_time){

    if(i>=arr.size() && t>=0){
        if(score>max_score){
            max_score = score;
            min_time = t;
        }
        else if(score == max_score){
            min_time = max(min_time,t);
        }
        return ;
    } 

    if(t-arr[i].first>=0)
    helper(arr,i+1,t-arr[i].first,score+arr[i].second,max_score,min_time);

    helper(arr,i+1,t,score,max_score,min_time);
}


